import{_ as r,o as a,c as t,ag as o}from"./chunks/framework.DGzMGr_a.js";const f=JSON.parse('{"title":"AI 应用 参考资料","description":"","frontmatter":{},"headers":[],"relativePath":"domains/ai/RESOURCES.md","filePath":"domains/ai/RESOURCES.md","lastUpdated":1783504823000}'),l={name:"domains/ai/RESOURCES.md"};function n(i,e,s,c,h,p){return a(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="ai-应用-参考资料" tabindex="-1">AI 应用 参考资料 <a class="header-anchor" href="#ai-应用-参考资料" aria-label="Permalink to &quot;AI 应用 参考资料&quot;">​</a></h1><p>LLM 应用、Agent、RAG、工具调用与安全的前端工程权威来源。API 行为以各厂商官方文档为准，协议以 Anthropic/OpenAI 公开规范为主。</p><h2 id="流式与-http" tabindex="-1">流式与 HTTP <a class="header-anchor" href="#流式与-http" aria-label="Permalink to &quot;流式与 HTTP&quot;">​</a></h2><ul><li><a href="https://developer.mozilla.org/en-US/docs/Web/API/Server-sent_events" target="_blank" rel="noreferrer">MDN: Server-sent events</a> — SSE 事件流与 <code>EventSource</code> API。Use for: 流式对话 UI、为何需要 fetch + ReadableStream。</li><li><a href="https://developer.mozilla.org/en-US/docs/Web/API/ReadableStream" target="_blank" rel="noreferrer">MDN: ReadableStream</a> — 流式读取响应体。Use for: LLM token 增量解析。</li><li><a href="https://fetch.spec.whatwg.org/" target="_blank" rel="noreferrer">Fetch Living Standard</a> — fetch、AbortController 取消请求。Use for: 中断生成、超时控制。</li><li><a href="https://platform.openai.com/docs/api-reference/streaming" target="_blank" rel="noreferrer">OpenAI API: Streaming</a> — OpenAI 兼容流式 chunk 格式。Use for: SSE 数据帧解析对照。</li></ul><h2 id="tool-use-与-agent" tabindex="-1">Tool Use 与 Agent <a class="header-anchor" href="#tool-use-与-agent" aria-label="Permalink to &quot;Tool Use 与 Agent&quot;">​</a></h2><ul><li><a href="https://platform.openai.com/docs/guides/function-calling" target="_blank" rel="noreferrer">OpenAI: Function calling</a> — 工具 schema 与模型选工具流程。Use for: function calling vs MCP 对比。</li><li><a href="https://docs.anthropic.com/en/docs/build-with-claude/tool-use" target="_blank" rel="noreferrer">Anthropic: Tool use</a> — Claude 工具调用与多步 agent。Use for: Agent loop 编排。</li><li><a href="https://modelcontextprotocol.io/introduction" target="_blank" rel="noreferrer">Model Context Protocol (MCP)</a> — MCP 协议定位与架构。Use for: MCP vs function calling。</li><li><a href="https://spec.modelcontextprotocol.io/" target="_blank" rel="noreferrer">MCP Specification</a> — 传输层与资源/工具抽象。Use for: Skills、MCP 深化。</li></ul><h2 id="上下文与-token" tabindex="-1">上下文与 Token <a class="header-anchor" href="#上下文与-token" aria-label="Permalink to &quot;上下文与 Token&quot;">​</a></h2><ul><li><a href="https://platform.openai.com/tokenizer" target="_blank" rel="noreferrer">OpenAI: Tokenizer</a> — token 计数可视化。Use for: token 预算、截断策略。</li><li><a href="https://docs.anthropic.com/en/docs/build-with-claude/prompt-caching" target="_blank" rel="noreferrer">Anthropic: Prompt caching</a> — 长上下文缓存实践。Use for: 上下文窗口管理。</li></ul><h2 id="rag-与安全" tabindex="-1">RAG 与安全 <a class="header-anchor" href="#rag-与安全" aria-label="Permalink to &quot;RAG 与安全&quot;">​</a></h2><ul><li><a href="https://owasp.org/www-project-top-10-for-large-language-model-applications/" target="_blank" rel="noreferrer">OWASP LLM Top 10</a> — LLM 应用安全风险总览。Use for: prompt injection、输出安全。</li><li><a href="https://owasp.org/www-project-top-10-for-large-language-model-applications/Archive/1_1_0/LLM01_2024-Prompt_Injection.html" target="_blank" rel="noreferrer">OWASP: Prompt Injection</a> — 注入攻击分类与缓解。Use for: 前端 + BFF 防护边界。</li><li><a href="https://web.dev/articles/what-are-embeddings" target="_blank" rel="noreferrer">web.dev: What are embeddings?</a> — 向量检索入门。Use for: RAG 前端展示与检索流程。</li></ul>',10)])])}const g=r(l,[["render",n]]);export{f as __pageData,g as default};
